-        if seq > self.highest_seen {
-            // New highest: slide window
-            let diff = seq - self.highest_seen;
-            if diff >= self.size {
-                self.seen_bitmap = 1;
-            } else {
-                self.seen_bitmap <<= diff;
-                self.seen_bitmap |= 1;
-            }
-            self.highest_seen = seq;
